// Loop over input items and add new fields called 'url1', 'url2', 'url3', etc.
items.forEach(item => {
    // Cari semua URL gambar yang sesuai dengan ekstensi gambar yang diinginkan
    const urls = item.json.output.match(/https?:\/\/[^\s]+(?:jpe?g|png|gif|webp|bmp|svg)/g);

    // Jika ada URL yang ditemukan, tambahkan ke dalam item
    if (urls) {
        urls.forEach((url, idx) => {
            item.json[`url${idx + 1}`] = url;
        });
    } else {
        // Jika tidak ada URL ditemukan, kosongkan output atau beri penanganan lain
        item.json.output = item.json.output.replace("\n", " ");  // Contoh pemrosesan jika tidak ada URL
    }
});

// Kembalikan input yang telah diproses
return items;

// Daftar kata kunci untuk proyek
const keywords = [
    "The Premiere at Sulfat",
    "The Premiere at Janti",
    "The Premiere at KS Tubun",
    "The Premiere at Landungsari",
    "The Premiere at Sartika"
];

// Ambil teks dari input
const inputText = $input.first().json.pesan;  // Ambil teks dari input
let foundKeyword = ''; // Inisialisasi foundKeyword

// Daftar proyek untuk perbandingan (text lengkap dengan deskripsi)
const allProjectsText = [
    "The Premiere at Sulfat di tengah kota Malang (Hunian Private Cluster dan Homestay Keluarga)",
    "The Premiere at Sartika di tengah kota wisata Batu (Luxury Villa & Retreat Living)",
    "The Premiere at KS Tubun di kota Malang (Hunian Private Cluster Asri & Homestay dengan fasilitas Clubhouse)",
    "The Premiere at Janti di kota Malang (Hunian Private Cluster & Rumah Kost)",
    "The Premiere at Landungsari di kota pendidikan Malang (Premium Rukost & Homestay)"
];

// Cek apakah semua proyek ditemukan dalam teks
const allProjectsFound = allProjectsText.every(project => inputText.includes(project));

// Tentukan apakah teks mengandung seluruh proyek atau tidak
if (allProjectsFound) {
    foundKeyword = ''; // Jika semua proyek ditemukan, kosongkan foundKeyword
} else {
    // Jika tidak semua proyek ditemukan, periksa kata kunci yang ditemukan dalam teks
    keywords.forEach(keyword => {
        if (inputText.toLowerCase().includes(keyword.toLowerCase())) {
            foundKeyword = keyword; // Menyimpan proyek yang ditemukan dalam foundKeyword
        }
    });
}

// Ambil URL dari input
const url = $input.first().json.url;  // Ambil URL dari input data

// Proses URL menggunakan regular expression (regex) untuk mengekstrak utm_source dan path
const utmSourceMatch = url.match(/[?&]utm_source=([^&]+)/);
const utmSource = utmSourceMatch ? utmSourceMatch[1] : null;

// Cek apakah path terdefinisi, jika tidak maka set ke string kosong
const pathMatch = url.match(/https?:\/\/[^\/]+(\/[^?]*)/);
const path = pathMatch ? pathMatch[1] : '';  // Jika path tidak ada, set ke string kosong

// Tentukan sumber berdasarkan utm_source atau URL
let source = '';

// Cek utm_source dulu
if (utmSource === 'facebook' || utmSource === 'instagram') {
  source = 'Meta Ads';
} 
// Cek gclid untuk Google Ads
else if (utmSource === 'google' || url.includes('gclid')) {
  source = 'Google Ads';
} 
// Tambahkan deteksi fb.me sebagai Meta Ads
else if (url.includes('fb.me') || url.includes('facebook.com')) {
  source = 'Meta Ads';
} 
// Landing page khusus
else if (path && path.includes('all-projects')) {
  source = 'Landing Page All Projects';
} 
else if (path && (path.includes('janti') || path.includes('sartika') || path.includes('landungsari') || path.includes('kstubun') || path.includes('sulfat'))) {
  source = 'Landing Page Project';
} 
else {
  source = 'Website';
}

// Tentukan proyek berdasarkan path URL
let project = '';
if (path && path.includes('janti')) {  // Pastikan path ada
  project = 'The Premiere at Janti';
} else if (path && path.includes('sartika')) {  // Pastikan path ada
  project = 'The Premiere at Sartika';
} else if (path && path.includes('landungsari')) {  // Pastikan path ada
  project = 'The Premiere at Landungsari';
} else if (path && path.includes('kstubun')) {  // Pastikan path ada
  project = 'The Premiere at KS Tubun';
} else if (path && path.includes('sulfat')) {  // Pastikan path ada
  project = 'The Premiere at Sulfat';
}

// Menampilkan hasil
