parameters.jsCode:
const rows = $input.all().map(x => x.json);

// helper aman
const s = v => (v === undefined || v === null) ? '' : String(v).trim();
const lower = v => s(v).toLowerCase();
const num = v => {
  const n = Number(s(v));
  return Number.isFinite(n) ? n : null;
};
const dt = v => {
  const t = Date.parse(s(v));
  return Number.isFinite(t) ? t : 0;
};

// 1) LEADS (DATA sheet)
const leads = rows.filter(r => {
  const st = lower(r.STATUS);
  return st === 'warm' || st === 'hot';
});

if (leads.length === 0) {
  return [{
    json: {
      _skip: true,
      reason: 'Tidak ada lead warm/hot'
    }
  }];
}

// 2) MARKETING LIST (DATAMARKETING)
const marketing = rows
  .filter(r => s(r['Nama Marketing']) !== '')
  .map(r => ({
    no: num(r.No) ?? 999999,
    name: s(r['Nama Marketing']),
    phone: s(r.Nomer)        // ✅ NOMER MARKETING
  }))
  .sort((a, b) => a.no - b.no);

if (marketing.length === 0) {
  throw new Error('Marketing kosong');
}

// 3) HISTORY (MARKETING assign)
const history = rows
  .filter(r =>
    s(r.tanggal_handle) !== '' &&
    (s(r.assign_to) !== '' || s(r.handle_by) !== '')
  )
  .map(r => ({
    when: dt(r.tanggal_handle),
    who: s(r.assign_to) || s(r.handle_by)
  }));

// 4) TENTUKAN POINTER
let pointer = 0;

if (history.length > 0) {
  history.sort((a, b) => b.when - a.when);
  const lastName = lower(history[0].who);

  const lastIdx = marketing.findIndex(
    m => lower(m.name) === lastName
  );

  pointer = lastIdx >= 0
    ? (lastIdx + 1) % marketing.length
    : 0;
}

// 5) NOMOR BARU
const maxNo = rows
  .map(r => num(r.No))
  .filter(v => v !== null)
  .reduce((a, b) => Math.max(a, b), 0);

// 6) ROUND ROBIN ASSIGN
const result = [];

for (let i = 0; i < leads.length; i++) {
  const lead = leads[i];
  const m = marketing[pointer];

  result.push({
    json: {
      No: maxNo + i + 1,
      tanggal_handle: new Date().toISOString(),
      handle_by: m.name,
      assign_to: m.name,
      nomer_marketing: m.phone,     // ✅ SIAP KIRIM KE MARKETING
      NAMA_user: s(lead.NAMA),
      nomer_user: s(lead['NOMOR HP']),
      STATUS: s(lead.STATUS),      // Add STATUS to output
      PROYEK: s(lead.PROYEK),      // Add PROYEK to output
    }
  });

  pointer = (pointer + 1) % marketing.length;
}

return result;

if ($('Code1').first().json.message === "Bicara dengan Agent") {
    return { agent_status: "off" };  // Menonaktifkan agen AI
} else {
    return { agent_status: "on" };   // Agen AI tetap aktif
}
